class ListNode:
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next

class SinglyLinkedList:
    def __init__(self):
        self.head = None

    # 1. Insert at Head - O(1)
    def insert_head(self, val):
        new_node = ListNode(val, self.head)
        self.head = new_node

    # 2. Insert at Tail - O(N) without tail pointer
    def insert_tail(self, val):
        new_node = ListNode(val)
        if not self.head:
            self.head = new_node
            return
        curr = self.head
        while curr.next:
            curr = curr.next
        curr.next = new_node

    # 3. Delete Node by Value - O(N)
    def delete_value(self, target):
        if not self.head:
            return
        if self.head.val == target:
            self.head = self.head.next
            return
        curr = self.head
        while curr.next and curr.next.val != target:
            curr = curr.next
        if curr.next:
            curr.next = curr.next.next

    # 4. Traverse & Search - O(N)
    def to_list(self):
        res = []
        curr = self.head
        while curr:
            res.append(curr.val)
            curr = curr.next
        return res

sll = SinglyLinkedList()
sll.insert_head(20)
sll.insert_head(10)
sll.insert_tail(30)
print(sll.to_list())   # [10, 20, 30]
sll.delete_value(20)
print(sll.to_list())   # [10, 30]

class DoublyListNode:
    def __init__(self, val=0, prev=None, next=None):
        self.val = val
        self.prev = prev
        self.next = next

class DoublyLinkedList:
    def __init__(self):
        self.head = None

    # 1. Insert at Head - O(1)
    def insert_head(self, val):
        new_node = DoublyListNode(val, next=self.head)
        if self.head:
            self.head.prev = new_node
        self.head = new_node

    # 2. Delete Node directly - O(1)
    def delete_node(self, node):
        if not node:
            return
        if node.prev:
            node.prev.next = node.next
        else:
            self.head = node.next
        if node.next:
            node.next.prev = node.prev
